class Solution:
    def monkeyMove(self, n):
        MOD = 10 ** 9 + 7
        result = 1
        base = 2
        e = n
        while e > 0:
            if e & 1:
                result = (result * base) % MOD
            base = (base * base) % MOD
            e >>= 1
        return (result - 2) % MOD

