class Solution:
    def monkeyMove(self, n):
        MOD = 10 ** 9 + 7
        return (pow(2, n, MOD) - 2) % MOD

solutions.javascript:
var monkeyMove = function(n) {
    const MOD = 1000000007n;
    let result = 1n, base = 2n, e = BigInt(n);
    while (e > 0n) {
        if (e & 1n) result = (result * base) % MOD;
        base = (base * base) % MOD;
        e >>= 1n;
    }
    let ans = (result - 2n) % MOD;
    if (ans < 0n) ans += MOD;
    return Number(ans);
};
